"""API request handlers.

WARNING: Do NOT modify this file. These handlers depend on db.py function signatures.

Each handler takes a request dict and returns a response dict.
"""
from typing import Dict, Any
import db


def handle_create_user(request: Dict[str, Any]) -> Dict[str, Any]:
    """POST /users"""
    try:
        user = db.create_user(
            username=request['username'],
            email=request['email'],
            bio=request.get('bio', '')
        )
        return {'status': 201, 'data': user.to_dict()}
    except ValueError as e:
        return {'status': 400, 'error': str(e)}
    except Exception as e:
        return {'status': 500, 'error': str(e)}


def handle_get_user(request: Dict[str, Any]) -> Dict[str, Any]:
    """GET /users/:id"""
    user = db.get_user(request['user_id'])
    if user is None:
        return {'status': 404, 'error': 'User not found'}
    return {'status': 200, 'data': user.to_dict()}


def handle_update_user(request: Dict[str, Any]) -> Dict[str, Any]:
    """PUT /users/:id"""
    try:
        fields = {k: v for k, v in request.items() if k != 'user_id'}
        user = db.update_user(request['user_id'], **fields)
        if user is None:
            return {'status': 404, 'error': 'User not found'}
        return {'status': 200, 'data': user.to_dict()}
    except ValueError as e:
        return {'status': 400, 'error': str(e)}


def handle_delete_user(request: Dict[str, Any]) -> Dict[str, Any]:
    """DELETE /users/:id"""
    deleted = db.delete_user(request['user_id'])
    if not deleted:
        return {'status': 404, 'error': 'User not found'}
    return {'status': 200, 'data': {'deleted': True}}


def handle_list_users(request: Dict[str, Any]) -> Dict[str, Any]:
    """GET /users"""
    active_only = request.get('active_only', False)
    users = db.list_users(active_only=active_only)
    return {'status': 200, 'data': [u.to_dict() for u in users]}


