"""Utility functions for the application."""
from datetime import datetime

_id_counters = {}


def now_iso() -> str:
    """Return current UTC time as ISO 8601 string."""
    return datetime.utcnow().isoformat() + 'Z'


def generate_id(namespace: str = 'default') -> int:
    """Generate an auto-incrementing integer ID for a namespace."""
    if namespace not in _id_counters:
        _id_counters[namespace] = 0
    _id_counters[namespace] += 1
    return _id_counters[namespace]


def truncate_string(s: str, max_len: int = 100) -> str:
    """Truncate a string to max_len, adding '...' if truncated."""
    if len(s) <= max_len:
        return s
    return s[:max_len - 3] + '...'


def format_date(iso_string: str) -> str:
    """Format an ISO date string to a human-readable format."""
    try:
        dt = datetime.fromisoformat(iso_string.replace('Z', '+00:00'))
        return dt.strftime('%B %d, %Y at %H:%M')
    except (ValueError, AttributeError):
        return iso_string


def sanitize_input(text: str) -> str:
    """Basic input sanitization — strip whitespace and limit length."""
    if not isinstance(text, str):
        return ''
    return text.strip()[:10000]
